#!/usr/bin/env python3
"""
generate-sketches.py — Standalone rank-K exclusion-sketch generator.

Phase A of the Standing-Wave Mesh rollout. Produces a single
`<model>-sketches.knot` artifact containing rank-K SVD sketches for every
2D weight matrix worth sketching (lm_head, token_embd, all attention
Q/K/V/O, all FFN gate/up/down). Lighter than running the full GKQ encoder
because it does NOT emit dense blocks or do per-layer Q4_K residuals — just
walks the safetensors shards one tensor at a time, runs randomized SVD at
the requested rank, quantizes, accumulates a SketchEntry.

Use when you want sketches without paying for a full GKQ re-encode of the
model — e.g. to seed sketches for production models already on R2 in Q4_K
form.

Memory: bounded by the largest single 2D tensor (typically `token_embd` =
vocab × hidden = 151936 × 896 f32 = 545 MB for Qwen-0.5B). Holds at most
one such tensor + its rank-K SVD factors at a time.

Usage:
    python3 generate-sketches.py \\
        --model Qwen/Qwen2.5-0.5B-Instruct \\
        --output rknots/qwen-0.5b-sketches.knot \\
        --rank 32

    python3 generate-sketches.py \\
        --model /path/to/local-hf-dir \\
        --output sketches.knot --rank 32

The output file has KNOT magic so fat-station's existing loader can
range-fetch sketches with zero loader-side changes; the dequantizer needs
to recognise the "SK32" tensor type (Phase B work).
"""

from __future__ import annotations

import argparse
import gc
import json
import os
import struct
import sys
import time
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import sketch_knot_format as skf  # noqa: E402

# Reuse name mapping + arch detection from encode-real-model.py for parity
# with the GKQ encoder. If the canonical-name scheme drifts, both must drift
# together.
import importlib.util  # noqa: E402

_legacy_spec = importlib.util.spec_from_file_location(
    "encode_real_model_legacy", str(_HERE / "encode-real-model.py")
)
_legacy = importlib.util.module_from_spec(_legacy_spec)
_legacy_spec.loader.exec_module(_legacy)  # type: ignore[union-attr]

map_tensor_name = _legacy.map_tensor_name
detect_arch = _legacy.detect_arch
build_knot_config = _legacy.build_knot_config
_sketch_quantize = _legacy._sketch_quantize
_should_sketch = _legacy._should_sketch


# ─────────────────────────────────────────────────────────────────────────────
# safetensors helpers (mirror encode-real-model-streaming.py to keep parity)
# ─────────────────────────────────────────────────────────────────────────────


def _resolve_model_dir(model_arg: str, cache_dir: str) -> Path:
    p = Path(model_arg)
    if p.is_dir() and any(p.glob("*.safetensors")):
        print(f"[hf] using local model dir: {p}")
        return p
    from huggingface_hub import snapshot_download
    cache = Path(cache_dir)
    cache.mkdir(parents=True, exist_ok=True)
    print(f"[hf] snapshot_download {model_arg} → {cache}")
    local = snapshot_download(
        repo_id=model_arg,
        cache_dir=str(cache),
        allow_patterns=["*.safetensors", "*.safetensors.index.json", "config.json"],
    )
    return Path(local)


# Shard-streaming HF download — only used when --shard-stream is set so we
# don't need the whole model on disk at once. Pulls one shard, processes it,
# deletes it before pulling the next.

def _hf_shard_stream_config(model_id: str, cache_dir: str):
    """Pull just config.json from the hub, parse it, return AutoConfig-like."""
    import importlib
    hub = importlib.import_module("huggingface_hub")
    cfg_path = hub.hf_hub_download(repo_id=model_id, filename="config.json", cache_dir=cache_dir)
    try:
        from transformers import AutoConfig  # type: ignore
        return AutoConfig.from_pretrained(str(Path(cfg_path).parent))
    except Exception:
        import json as _json
        with open(cfg_path) as f:
            cfg_dict = _json.load(f)
        class _Cfg:
            pass
        cfg = _Cfg()
        for k, v in cfg_dict.items():
            setattr(cfg, k, v)
        return cfg


def _hf_shard_stream_index(model_id: str, cache_dir: str):
    """Return tensor_name -> shard_filename. If no index file, return None
    (single-shard repos)."""
    import importlib
    import json as _json
    hub = importlib.import_module("huggingface_hub")
    try:
        index_path = hub.hf_hub_download(
            repo_id=model_id, filename="model.safetensors.index.json", cache_dir=cache_dir,
        )
    except Exception:
        return None
    with open(index_path) as f:
        idx = _json.load(f)
    return idx.get("weight_map", {})


def _hf_shard_stream_download(model_id: str, filename: str, cache_dir: str) -> str:
    import importlib
    hub = importlib.import_module("huggingface_hub")
    return hub.hf_hub_download(repo_id=model_id, filename=filename, cache_dir=cache_dir)


def _hf_shard_stream_delete(local_path: str) -> None:
    """Delete a downloaded shard (both the symlink in snapshots/ and the
    blob it points to under blobs/). Mirrors encode-real-model-hfstream.py."""
    try:
        real = os.path.realpath(local_path)
        if os.path.exists(real):
            os.remove(real)
        if os.path.islink(local_path):
            os.unlink(local_path)
        elif os.path.exists(local_path) and real != local_path:
            os.remove(local_path)
    except OSError as e:
        print(f"[sketch] WARN: could not remove {local_path}: {e}")


def _load_shard_map(model_dir: Path) -> Dict[str, str]:
    from safetensors import safe_open
    import json as _json
    index = model_dir / "model.safetensors.index.json"
    if index.exists():
        with open(index) as f:
            idx = _json.load(f)
        weight_map = idx.get("weight_map", {})
        return {tname: str(model_dir / sh) for tname, sh in weight_map.items()}
    shards = sorted(model_dir.glob("*.safetensors"))
    if not shards:
        raise FileNotFoundError(f"no *.safetensors under {model_dir}")
    out: Dict[str, str] = {}
    for shard in shards:
        with safe_open(str(shard), framework="numpy", device="cpu") as f:
            for tname in f.keys():
                out[tname] = str(shard)
    return out


def _load_safetensors_header(shard_path: str) -> Tuple[int, Dict[str, dict]]:
    """Read safetensors metadata without mmaping the tensor payload."""
    with open(shard_path, "rb") as f:
        raw_len = f.read(8)
        if len(raw_len) != 8:
            raise ValueError(f"{shard_path}: missing safetensors header length")
        header_len = struct.unpack("<Q", raw_len)[0]
        raw_header = f.read(header_len)
    header = json.loads(raw_header.decode("utf-8"))
    tensors = {
        key: value
        for key, value in header.items()
        if key != "__metadata__"
    }
    return int(header_len), tensors


def _decode_safetensor_slice(dtype: str, payload: bytes) -> np.ndarray:
    """Decode a raw safetensors payload slice to float32."""
    normalized = dtype.upper()
    if normalized == "BF16":
        raw = np.frombuffer(payload, dtype="<u2")
        return (raw.astype(np.uint32) << 16).view(np.float32)
    if normalized == "F16":
        return np.frombuffer(payload, dtype="<f2").astype(np.float32)
    if normalized == "F32":
        return np.frombuffer(payload, dtype="<f4").astype(np.float32, copy=False)
    if normalized == "F64":
        return np.frombuffer(payload, dtype="<f8").astype(np.float32)
    raise ValueError(f"unsupported safetensors dtype for sketching: {dtype}")


def _fetch_safetensor_2d_f32(
    shard_path: str,
    tensor_name: str,
    header_len: int,
    tensors: Dict[str, dict],
) -> np.ndarray:
    """Read exactly one tensor from a safetensors shard without mmap."""
    info = tensors.get(tensor_name)
    if info is None:
        raise KeyError(f"{tensor_name} not found in {shard_path}")
    dtype = info.get("dtype")
    shape = info.get("shape")
    offsets = info.get("data_offsets")
    if not isinstance(dtype, str) or not isinstance(shape, list) \
            or not isinstance(offsets, list) or len(offsets) != 2:
        raise ValueError(f"{tensor_name}: malformed safetensors metadata")
    start = int(offsets[0])
    end = int(offsets[1])
    if end < start:
        raise ValueError(f"{tensor_name}: negative payload length")
    with open(shard_path, "rb") as f:
        f.seek(8 + header_len + start)
        payload = f.read(end - start)
    if len(payload) != end - start:
        raise IOError(
            f"{tensor_name}: read {len(payload)} bytes, expected {end - start}"
        )
    arr = _decode_safetensor_slice(dtype, payload)
    return arr.reshape(tuple(int(dim) for dim in shape))


def _load_hf_config(model_dir: Path):
    import json as _json
    cfg_path = model_dir / "config.json"
    if not cfg_path.exists():
        raise FileNotFoundError(f"missing config.json in {model_dir}")
    try:
        from transformers import AutoConfig  # type: ignore
        return AutoConfig.from_pretrained(str(model_dir))
    except Exception:
        with open(cfg_path) as f:
            cfg_dict = _json.load(f)
        class _Cfg:
            pass
        cfg = _Cfg()
        for k, v in cfg_dict.items():
            setattr(cfg, k, v)
        return cfg


def _fetch_2d_tensor_f32(shard_path: str, tensor_name: str) -> np.ndarray:
    """Read one tensor as numpy float32. Promotes bf16/f16 exactly (bf16 via
    16-bit shift into the high half of f32; f16 via numpy cast)."""
    try:
        header_len, tensors = _load_safetensors_header(shard_path)
        return _fetch_safetensor_2d_f32(
            shard_path,
            tensor_name,
            header_len,
            tensors,
        )
    except Exception as manual_error:
        print(
            f"[sketch] WARN: direct safetensors read failed for {tensor_name}: "
            f"{manual_error}; falling back to safetensors safe_open"
        )
    from safetensors import safe_open
    # numpy framework gives us zero-torch dependency. bf16 is not numpy-native;
    # safetensors framework="numpy" raises on bf16. We try numpy first and fall
    # back to torch when we hit bf16.
    try:
        with safe_open(shard_path, framework="numpy", device="cpu") as f:
            arr = f.get_tensor(tensor_name)
        if arr.dtype == np.float16:
            return arr.astype(np.float32, copy=False)
        if arr.dtype == np.float32:
            return arr
        # Other numpy dtypes (rare for weight tensors): cast.
        return arr.astype(np.float32, copy=False)
    except Exception:
        import torch
        with safe_open(shard_path, framework="pt", device="cpu") as f:
            t = f.get_tensor(tensor_name)
        if t.dtype == torch.bfloat16:
            t = t.to(torch.float32)
        elif t.dtype == torch.float16:
            t = t.to(torch.float32)
        return t.detach().cpu().numpy()


# ─────────────────────────────────────────────────────────────────────────────
# Sketch generation pass
# ─────────────────────────────────────────────────────────────────────────────


def generate_sketches_hub_stream(
    *,
    model_id: str,
    model_name: str,
    output_path: str,
    max_layers: Optional[int],
    rank: int,
    cache_dir: str,
    min_free_gb: float = 6.0,
    stream_output: bool = False,
    spool_dir: Optional[str] = None,
    reconstruction_check: str = "full",
) -> dict:
    """One-shard-at-a-time hub streaming. Suitable when the full model won't
    fit on disk (e.g. Qwen-Coder-7B = ~20 GB on a 12 GB free volume)."""
    import shutil
    hf_config = _hf_shard_stream_config(model_id, cache_dir)
    arch = detect_arch(hf_config)
    knot_config = build_knot_config(hf_config, arch, max_layers)
    tie_word_embeddings = bool(getattr(hf_config, "tie_word_embeddings", False))

    weight_map = _hf_shard_stream_index(model_id, cache_dir)
    if weight_map is None:
        raise RuntimeError(
            "Single-shard repo: use --model with --shard-stream omitted "
            "(snapshot_download path is fine for single-shard models)."
        )
    print(f"[sketch] arch={arch} tie_word_embeddings={tie_word_embeddings}")
    print(f"[sketch] {len(weight_map)} repo tensors across "
          f"{len(set(weight_map.values()))} shards")

    # Group by shard so we sketch every relevant tensor in a shard before
    # moving on (avoids re-downloading).
    shard_to_tensors: Dict[str, List[Tuple[str, str]]] = {}
    for hf_name, shard_name in weight_map.items():
        mapped = map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, _kind = mapped
        if not _should_sketch(canonical):
            continue
        shard_to_tensors.setdefault(shard_name, []).append((canonical, hf_name))

    total_targets = sum(len(v) for v in shard_to_tensors.values())
    print(f"[sketch] sketching {total_targets} tensors at rank={rank} across "
          f"{len(shard_to_tensors)} shards")

    sketches: List[skf.SketchEntry] = []
    spooled_writer: Optional[skf.SpooledSketchesKnotWriter] = None
    if stream_output:
        spooled_writer = skf.SpooledSketchesKnotWriter(spool_dir=spool_dir)
        print(f"[sketch] stream-output enabled: payload spool={spooled_writer.payload_path}")
    token_embd_alias_source: Optional[skf.SketchEntry] = None
    seen: set = set()
    worst_err = 0.0
    worst_err_name = ""
    t_start = time.time()
    t_last = t_start
    done = 0

    for shard_idx, shard_name in enumerate(sorted(shard_to_tensors)):
        # Failsafe: if free disk would dip below `min_free_gb` after the
        # shard lands, bail rather than fill the volume.
        free = shutil.disk_usage(cache_dir).free / (1024 ** 3)
        if free < min_free_gb:
            raise RuntimeError(
                f"sketch disk failsafe: free={free:.1f} GB < {min_free_gb:.1f} GB "
                f"before shard {shard_name}"
            )
        t_dl = time.time()
        local = _hf_shard_stream_download(model_id, shard_name, cache_dir)
        dl_s = time.time() - t_dl
        try:
            shard_sz_gb = os.path.getsize(local) / 1e9
        except OSError:
            shard_sz_gb = 0.0
        print(f"[sketch] shard {shard_idx+1}/{len(shard_to_tensors)} "
              f"{shard_name}  size={shard_sz_gb:.2f} GB  dl={dl_s:.1f}s")

        header_len, tensors = _load_safetensors_header(local)
        for canonical, hf_name in sorted(shard_to_tensors[shard_name]):
            if canonical in seen:
                continue
            arr = _fetch_safetensor_2d_f32(
                local,
                hf_name,
                header_len,
                tensors,
            )
            if arr.ndim != 2:
                arr = arr.reshape(arr.shape[0], -1)
            d_out, d_in = arr.shape
            entry = _sketch_quantize(arr, rank=int(rank))
            entry.name = canonical
            if canonical == "token_embd.weight":
                token_embd_alias_source = entry
            if spooled_writer is None:
                sketches.append(entry)
            else:
                spooled_writer.add(entry)
            seen.add(canonical)
            if reconstruction_check == "full":
                # Expensive: reconstructs the full dense matrix. Keep disabled
                # for 70B-class runs, where this can double peak memory.
                W_rec = skf.reconstruct_sketch(
                    entry.u_q8, entry.sigma_q8, entry.v_q8,
                    entry.u_max, entry.sigma_max, entry.v_max,
                )
                rel_err = float(np.linalg.norm(arr - W_rec) / (np.linalg.norm(arr) + 1e-12))
                if rel_err > worst_err:
                    worst_err = rel_err
                    worst_err_name = canonical
                del W_rec
            else:
                rel_err = None
            del arr
            gc.collect()
            done += 1
            now = time.time()
            if now - t_last > 10.0 or done == total_targets:
                rate = done / (now - t_start) if (now - t_start) > 0 else 0
                rel_err_text = "skipped" if rel_err is None else f"{rel_err:.4f}"
                print(f"[sketch] {done}/{total_targets}  "
                      f"({canonical}: {d_out}×{d_in}→r{entry.rank}, "
                      f"rel_err={rel_err_text})  "
                      f"avg {rate:.1f} tensors/s  worst_err={worst_err:.4f}", flush=True)
                t_last = now

        # Delete this shard before the next download.
        _hf_shard_stream_delete(local)

    # Tied embeddings cloning.
    if tie_word_embeddings and "output.weight" not in seen and "token_embd.weight" in seen:
        src = token_embd_alias_source
        if src is None:
            src = next((s for s in sketches if s.name == "token_embd.weight"), None)
        if src is None:
            raise RuntimeError("tie_word_embeddings set but token_embd sketch was not retained")
        clone = skf.SketchEntry(
            name="output.weight",
            d_out=src.d_out, d_in=src.d_in, rank=src.rank,
            u_q8=src.u_q8.copy(), sigma_q8=src.sigma_q8.copy(), v_q8=src.v_q8.copy(),
            u_max=src.u_max, sigma_max=src.sigma_max, v_max=src.v_max,
        )
        if spooled_writer is None:
            sketches.append(clone)
        else:
            spooled_writer.add(clone)
        print(f"[sketch] tied weights: cloned output.weight ← token_embd.weight")

    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    if spooled_writer is None:
        sk_summary = skf.write_sketches_knot(
            str(out_path),
            model_name=model_name,
            source_config=knot_config,
            sketches=sketches,
            sketch_rank_default=int(rank),
        )
    else:
        sk_summary = spooled_writer.write(
            str(out_path),
            model_name=model_name,
            source_config=knot_config,
            sketch_rank_default=int(rank),
        )
    sk_summary["elapsed_sec"] = time.time() - t_start
    sk_summary["worst_reconstruction_error"] = worst_err
    sk_summary["worst_reconstruction_error_name"] = worst_err_name
    return sk_summary


def generate_sketches(
    *,
    model_dir: Path,
    model_name: str,
    output_path: str,
    max_layers: Optional[int],
    rank: int,
    stream_output: bool = False,
    spool_dir: Optional[str] = None,
    reconstruction_check: str = "full",
) -> dict:
    hf_config = _load_hf_config(model_dir)
    arch = detect_arch(hf_config)
    knot_config = build_knot_config(hf_config, arch, max_layers)
    tie_word_embeddings = bool(getattr(hf_config, "tie_word_embeddings", False))

    shard_map = _load_shard_map(model_dir)
    print(f"[sketch] arch={arch} tie_word_embeddings={tie_word_embeddings} "
          f"num_layers={knot_config.get('num_layers')}")
    print(f"[sketch] {len(shard_map)} tensors across "
          f"{len(set(shard_map.values()))} shard(s)")

    # Classify, drop layers past max, dedupe canonical names.
    # NOTE: we deliberately do NOT filter to spectral-only here. Sketch coverage
    # includes the dense globals (token_embd / output) too — that's the
    # bandwidth-sensitive lm_head matrix.
    classified: List[Tuple[str, str]] = []  # (canonical, hf_name)
    seen: Dict[str, str] = {}
    for hf_name in shard_map:
        mapped = map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, _kind = mapped
        if not _should_sketch(canonical):
            continue
        if canonical in seen:
            continue
        seen[canonical] = hf_name
        classified.append((canonical, hf_name))

    # Tied embeddings: clone the embed sketch into output.weight when lm_head
    # is omitted from the HF state_dict. We do this AFTER the main pass so the
    # clone reuses the already-quantized sketch (faster + identical).
    must_clone_output = False
    if tie_word_embeddings and "output.weight" not in seen and "token_embd.weight" in seen:
        must_clone_output = True
        print("[sketch] tied weights: will alias output.weight ← token_embd.weight")

    classified.sort(key=lambda x: x[0])
    print(f"[sketch] sketching {len(classified)} tensors at rank={rank}")

    sketches: List[skf.SketchEntry] = []
    spooled_writer: Optional[skf.SpooledSketchesKnotWriter] = None
    if stream_output:
        spooled_writer = skf.SpooledSketchesKnotWriter(spool_dir=spool_dir)
        print(f"[sketch] stream-output enabled: payload spool={spooled_writer.payload_path}")
    token_embd_alias_source: Optional[skf.SketchEntry] = None
    worst_err = 0.0
    worst_err_name = ""
    t0 = time.time()
    last_progress = t0

    for i, (canonical, hf_name) in enumerate(classified):
        shard = shard_map[hf_name]
        arr = _fetch_2d_tensor_f32(shard, hf_name)
        if arr.ndim != 2:
            arr = arr.reshape(arr.shape[0], -1)
        d_out, d_in = arr.shape
        entry = _sketch_quantize(arr, rank=int(rank))
        entry.name = canonical
        if canonical == "token_embd.weight":
            token_embd_alias_source = entry
        if spooled_writer is None:
            sketches.append(entry)
        else:
            spooled_writer.add(entry)
        if reconstruction_check == "full":
            # Expensive: reconstructs the full dense matrix. Keep disabled
            # for 70B-class runs, where this can double peak memory.
            W_rec = skf.reconstruct_sketch(
                entry.u_q8, entry.sigma_q8, entry.v_q8,
                entry.u_max, entry.sigma_max, entry.v_max,
            )
            rel_err = float(np.linalg.norm(arr - W_rec) / (np.linalg.norm(arr) + 1e-12))
            if rel_err > worst_err:
                worst_err = rel_err
                worst_err_name = canonical
            del W_rec
        else:
            rel_err = None
        del arr
        gc.collect()

        now = time.time()
        if now - last_progress > 5.0 or i == len(classified) - 1:
            elapsed = now - t0
            rate = (i + 1) / elapsed if elapsed > 0 else 0
            rel_err_text = "skipped" if rel_err is None else f"{rel_err:.4f}"
            print(f"[sketch] {i+1}/{len(classified)}  "
                  f"({canonical}: {d_out}×{d_in}→r{entry.rank}, "
                  f"rel_err={rel_err_text})  "
                  f"avg {rate:.1f} tensors/s  worst_err={worst_err:.4f}")
            last_progress = now

    if must_clone_output:
        src = token_embd_alias_source
        if src is None:
            src = next((s for s in sketches if s.name == "token_embd.weight"), None)
        if src is not None:
            clone = skf.SketchEntry(
                name="output.weight",
                d_out=src.d_out, d_in=src.d_in, rank=src.rank,
                u_q8=src.u_q8.copy(), sigma_q8=src.sigma_q8.copy(), v_q8=src.v_q8.copy(),
                u_max=src.u_max, sigma_max=src.sigma_max, v_max=src.v_max,
            )
            if spooled_writer is None:
                sketches.append(clone)
            else:
                spooled_writer.add(clone)

    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    if spooled_writer is None:
        sk_summary = skf.write_sketches_knot(
            str(out_path),
            model_name=model_name,
            source_config=knot_config,
            sketches=sketches,
            sketch_rank_default=int(rank),
        )
    else:
        sk_summary = spooled_writer.write(
            str(out_path),
            model_name=model_name,
            source_config=knot_config,
            sketch_rank_default=int(rank),
        )
    elapsed_total = time.time() - t0
    sk_summary["elapsed_sec"] = elapsed_total
    sk_summary["worst_reconstruction_error"] = worst_err
    sk_summary["worst_reconstruction_error_name"] = worst_err_name
    return sk_summary


def _print_summary(s: dict) -> None:
    print("─" * 64)
    print(f"sketches knot written: {s['output_path']}")
    print(f"  size:         {s['file_size_mb']:.2f} MB ({s['file_size_bytes']:,} bytes)")
    print(f"  sketches:     {s['num_sketches']}")
    print(f"  meta bytes:   {s['metadata_bytes']:,}")
    print(f"  payload:      {s['payload_bytes']:,} bytes")
    print(f"  worst rel-err: {s.get('worst_reconstruction_error', 0):.4f}  "
          f"({s.get('worst_reconstruction_error_name', '')})")
    print(f"  elapsed:      {s.get('elapsed_sec', 0):.1f}s")
    print("─" * 64)


def parse_args(argv=None):
    p = argparse.ArgumentParser(description="Generate rank-K exclusion sketches for an HF model.")
    p.add_argument("--model", required=True,
                   help="HF model id (e.g. Qwen/Qwen2.5-0.5B-Instruct) or local dir")
    p.add_argument("--output", required=True, help="Output <model>-sketches.knot path")
    p.add_argument("--model-name", default=None,
                   help="Override model name in the metadata (default: --model)")
    p.add_argument("--max-layers", type=int, default=None,
                   help="Only sketch the first N transformer layers")
    p.add_argument("--rank", type=int, default=32,
                   help="Sketch rank (default 32). See GKQHelixBandwidth.lean Section 7.")
    p.add_argument("--cache-dir", default=os.environ.get("HF_HOME", str(Path.home() / ".cache/huggingface/hub")),
                   help="HF snapshot cache dir (default: $HF_HOME or ~/.cache/huggingface/hub)")
    p.add_argument("--shard-stream", action="store_true",
                   help=("Download one shard at a time, sketch it, then delete it before "
                         "the next download. Use for models too big to fully cache "
                         "(e.g. Qwen-Coder-7B = ~20 GB on a 12 GB free volume)."))
    p.add_argument("--min-free-gb", type=float, default=6.0,
                   help="Shard-stream failsafe: abort if free disk drops below this")
    p.add_argument("--stream-output", action="store_true",
                   help=("Spool sketch payloads to disk while generating instead of "
                         "holding every SketchEntry in RAM. Use for 70B-class runs."))
    p.add_argument("--spool-dir", default=os.environ.get("SKETCH_SPOOL_DIR"),
                   help="Temp directory for --stream-output payload spool")
    p.add_argument("--reconstruction-check", choices=("full", "none"), default="full",
                   help=("Diagnostic reconstruction mode. 'full' reconstructs every "
                         "dense tensor and doubles peak memory; use 'none' for 70B."))
    return p.parse_args(argv)


def main(argv=None) -> int:
    args = parse_args(argv)
    if args.shard_stream:
        summary = generate_sketches_hub_stream(
            model_id=args.model,
            model_name=args.model_name or args.model,
            output_path=args.output,
            max_layers=args.max_layers,
            rank=args.rank,
            cache_dir=args.cache_dir,
            min_free_gb=args.min_free_gb,
            stream_output=args.stream_output,
            spool_dir=args.spool_dir,
            reconstruction_check=args.reconstruction_check,
        )
    else:
        model_dir = _resolve_model_dir(args.model, args.cache_dir)
        summary = generate_sketches(
            model_dir=model_dir,
            model_name=args.model_name or args.model,
            output_path=args.output,
            max_layers=args.max_layers,
            rank=args.rank,
            stream_output=args.stream_output,
            spool_dir=args.spool_dir,
            reconstruction_check=args.reconstruction_check,
        )
    _print_summary(summary)
    return 0


if __name__ == "__main__":
    os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")
    os.environ.setdefault("OMP_NUM_THREADS", "1")
    raise SystemExit(main())
